require "config.Define"
require "config.RewardConfig"

local GUIAd = class("UIAd", IGUILayout)

function GUIAd:onLoad()
    self.type = Define.AdType.AD_NONE
    self.reward = {}
    self.delayTime = 0
    self.canShowReward = false
    self.waitRewardTime = 0
    self.tipTime = 0

    self.ad_card_times = 0
    self.ad_card_time = 0
    self.ad_prop_time = 0
    self.ad_prop_times = 0

    --StaticText
    self.tvTitle = self:getChildWindow("LuckySkyHallAd-Title", GUIType.StaticText)
    self.tvDesc = self:getChildWindow("LuckySkyHallAd-Desc", GUIType.StaticText)
    self.tvClickText = self:getChildWindow("LuckySkyHallAd-Result-Click-Text", GUIType.StaticText)
    self.tvTip = self:getChildWindow("LuckySkyHallAd-Tip", GUIType.StaticText)
    self.tvTip:SetVisible(false)
    self.tvNameText = self:getChildWindow("LuckySkyHallAd-Name-Text", GUIType.StaticText)
    self.tvPropName = self:getChildWindow("LuckySkyHallAd-Prop-Name", GUIType.StaticText)

    --StaticImage
    self.ivBg = self:getChildWindow("LuckySkyHallAd-Bg", GUIType.StaticImage)
    self.ivStaticCard = self:getChildWindow("LuckySkyHallAd-Static-Card", GUIType.StaticImage)

    self.ivEffect = self:getChildWindow("LuckySkyHallAd-Effect", GUIType.StaticImage)
    self.ivPropEffect = self:getChildWindow("LuckySkyHallAd-Prop-Effect", GUIType.StaticImage)
    self.ivCardEffect = self:getChildWindow("LuckySkyHallAd-Card-Effect", GUIType.StaticImage)

    self.ivPropReward = self:getChildWindow("LuckySkyHallAd-Prop-Reward", GUIType.StaticImage)
    self.ivPropIcon = self:getChildWindow("LuckySkyHallAd-Prop-Icon", GUIType.StaticImage)

    --Button
    self.btnWatch = self:getChildWindow("LuckySkyHallAd-Btn-Ad", GUIType.Button)

    --Layout
    self.llResult = self:getChildWindow("LuckySkyHallAd-Result", GUIType.Layout)
    self.llContent = self:getChildWindow("LuckySkyHallAd-Content", GUIType.Layout)

    --EffectViewOfObtainment
    self.eivCardReward = self:getChildWindow("LuckySkyHallAd-Card-Reward", GUIType.EffectViewOfObtainment)

    --ActorWindow
    self.awBoxActor = self:getChildWindow("LuckySkyHallAd-Modle-Prop", GUIType.ActorWindow)

    self.llContent:SetVisible(false)
    self.llResult:SetVisible(false)

    self:getChildWindow("LuckySkyHallAd-Watch-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.ad.watch.button.text"))
    self:getChildWindow("LuckySkyHallAd-Prop-Title", GUIType.StaticText):SetText(Lang:getString("lucky.sky.ad.prop.get.reward.text"))
    self:getChildWindow("LuckySkyHallAd-Prop-Tip", GUIType.StaticText):SetText(Lang:getString("lucky.sky.ad.prop.reward.tip"))

    self:getChildWindow("LuckySkyHallAd-Close", GUIType.Layout):registerEvent(GUIEvent.Click, function()
        self:onCloseClick()
    end)
    self.btnWatch:registerEvent(GUIEvent.ButtonClick, function()
        self:onWatch()
    end)
    self.awBoxActor:registerEvent(GUIEvent.Click, function()
        self:onRewardClick()
    end)
    self.ivStaticCard:registerEvent(GUIEvent.Click, function()
        self:onRewardClick()
    end)

    self:registerDataCallBack("SendAdvertRewardData", function(data)
        self:onWatchAdFinish(data)
    end, DataBuilderProcessor)

    self:registerDataCallBack("OpenUIData", function(data)
        self:openUIData(data)
    end, DataBuilderProcessor)

    self:registerDataCallBack("SendAdvertData", function(data)
        self:onSyncAdvertData(data)
    end, DataBuilderProcessor)
end

function GUIAd:openUIData(data)
    local type = data:getNumberParam("type")
    if type == Define.UIType.AD_Job then
        self:show(Define.AdType.AD_CARD)
    elseif type == Define.UIType.AD_Prop then
        self:show(Define.AdType.AD_PROP)
    end
end

function GUIAd:onTick(nTimeElapse)
    self:updateDelay(nTimeElapse)
    self:updateAdTime(nTimeElapse)
    self:updateTipTime(nTimeElapse)
    self:updateWaitRewardTime(nTimeElapse)
end

function GUIAd:updateDelay(nTimeElapse)
    if self.delayTime == 0 then
        return
    end

    if not self:isShow() then
        self.delayTime = 0
        return
    end

    self.delayTime = self.delayTime - nTimeElapse
    if self.delayTime <= 0 then
        self.delayTime = 0
        self:showReward()
    end
end

function GUIAd:updateWaitRewardTime(nTimeElapse)
    if self.waitRewardTime == 0 then
        return
    end

    self.waitRewardTime = self.waitRewardTime - nTimeElapse
    if self.waitRewardTime <= 0 then
        self.waitRewardTime = 0
    end
end

function GUIAd:updateAdTime(nTimeElapse)
    if self.ad_card_time > 0 then
        self.ad_card_time = self.ad_card_time - nTimeElapse
        if self.ad_card_time <= 0 then
            self.ad_card_time = 0
        end
    end

    if self.ad_prop_time > 0 then
        self.ad_prop_time = self.ad_prop_time - nTimeElapse
        if self.ad_prop_time <= 0 then
            self.ad_prop_time = 0
        end
    end
end

function GUIAd:updateTipTime(nTimeElapse)
    if self.tipTime == 0 then
        return
    end

    self.tipTime = self.tipTime - nTimeElapse
    if self.tipTime <= 0 then
        self.tvTip:SetVisible(false)
    end
end

function GUIAd:onShow(type)
    self.type = tonumber(type)
    self.llContent:SetVisible(true)
    self.llResult:SetVisible(false)
    self.ivEffect:SetVisible(true)
    self.tvTip:SetVisible(false)

    if type == Define.AdType.AD_CARD then
        self.ivEffect:SetEffectName("168_kapai.effect")
        self.ivCardEffect:SetVisible(true)
        self.ivCardEffect:SetEffectName("168_kapai01.effect")

        self.tvTitle:SetText(Lang:getString("lucky.sky.ad.card.title"))
        self.tvDesc:SetText(Lang:getString("lucky.sky.ad.card.desc"))
        self.ivBg:SetImage("set:lucky_sky_ad.json image:bg_card")

    elseif type == Define.AdType.AD_PROP then
        self.ivEffect:SetEffectName("172_fangkuai.effect")

        self.tvTitle:SetText(Lang:getString("lucky.sky.ad.prop.title"))
        self.tvDesc:SetText(Lang:getString("lucky.sky.ad.prop.desc"))
        self.ivBg:SetImage("set:lucky_sky_ad.json image:bg_prop")

    else
        self:hide()
    end
end

function GUIAd:onWatch()
    if self.type == Define.AdType.AD_NONE then
        return
    end

    if self.type == Define.AdType.AD_CARD then
        if self.ad_card_times <= 0 or
                (self.ad_card_times > 0 and self.ad_card_time > 0) then
            self:sendTip(Lang:getString("lucky.sky.ad.card.no.times.text"))
            return
        end
    elseif self.type == Define.AdType.AD_PROP then
        if self.ad_prop_times <= 0 or
                (self.ad_prop_times > 0 and self.ad_prop_time > 0) then
            self:sendTip(Lang:getString("lucky.sky.ad.prop.no.times.text"))
            return
        end
    end

    ClientHelper.onWatchAd(self.type)
end

function GUIAd:sendTip(msg)
    self.tipTime = 3000
    self.tvTip:SetText(msg)
    self.tvTip:SetVisible(true)
end

function GUIAd:onSyncAdvertData(data)
    local type = data:getNumberParam("type")
    if type == Define.AdType.AD_CARD then
        self.ad_card_times = data:getNumberParam("times")
        self.ad_card_time = data:getNumberParam("time")

    elseif type == Define.AdType.AD_PROP then
        self.ad_prop_times = data:getNumberParam("times")
        self.ad_prop_time = data:getNumberParam("time")
    end
end

function GUIAd:onWatchAdFinish(data)
    local rewardId = data:getNumberParam("rewardId")
    local reward = RewardConfig:getRewardById(rewardId)
    if reward == nil then
        self:hide()
        return
    end
    self.canShowReward = true
    self.llContent:SetVisible(false)
    self.eivCardReward:SetVisible(false)
    self.ivPropReward:SetVisible(false)
    self.tvClickText:SetVisible(true)
    self.ivPropEffect:SetVisible(false)
    self.ivCardEffect:SetVisible(false)
    self.llResult:SetVisible(true)

    local type = data:getNumberParam("type")
    self.reward = reward
    if type == Define.AdType.AD_CARD then
        self.awBoxActor:SetVisible(false)
        self.ivStaticCard:SetVisible(true)
        self.ivCardEffect:SetVisible(true)
        self.tvClickText:SetText(Lang:getString("lucky.sky.ad.card.click.text"))

    elseif type == Define.AdType.AD_PROP then
        self.awBoxActor:PlaySkill("idle")
        self.awBoxActor:SetVisible(true)
        self.ivStaticCard:SetVisible(false)
        self.tvClickText:SetText(Lang:getString("lucky.sky.ad.prop.click.text"))

    else
        self:hide()
    end
end

function GUIAd:onRewardClick()
    if self.canShowReward == false then
        self:hide()
        return
    end

    if self.type == Define.AdType.AD_CARD then
        self.delayTime = 0
        self:showReward()
        self.waitRewardTime = 1500

    elseif self.type == Define.AdType.AD_PROP then
        self.delayTime = 1500
        self.awBoxActor:PlaySkill("static")
        self.waitRewardTime = 2500
    else
        self:hide()
    end
    self.canShowReward = false
end

function GUIAd:showReward()
    self.awBoxActor:SetVisible(false)
    self.ivStaticCard:SetVisible(false)
    self.ivCardEffect:SetVisible(false)
    self.ivPropReward:SetVisible(false)

    if self.type == Define.AdType.AD_CARD then
        self.eivCardReward:SetVisible(true)
        self.eivCardReward:SetImage(self.reward.icon)
        self.tvNameText:SetText(Lang:getString(self.reward.name))
        self.tvClickText:SetVisible(false)
        LuaTimer:schedule(function ()
            self.ivCardEffect:SetVisible(true)
        end, 480)

    elseif self.type == Define.AdType.AD_PROP then
        self.ivPropEffect:SetVisible(true)
        self.ivPropEffect:SetEffectName("172_fangkuai02.effect")
        LuaTimer:schedule(function ()
            self.ivPropEffect:SetVisible(false)
            self.ivPropReward:SetVisible(true)
        end, 800)
        if self.reward.icon ~= "#" then
            self.ivPropIcon:SetImage(self.reward.icon)
        else
            local itemId = ItemConfig:getItemIdById(self.reward.rewardId)
            GuiItemStack.showItemIcon(self.ivPropIcon, tonumber(itemId), 0, "")
        end
        self.tvPropName:SetText(Lang:getString(self.reward.name) .. " x" .. self.reward.count)
        self.tvClickText:SetVisible(false)
    else
        self:hide()
    end
end

function GUIAd:onCloseClick()
    if self.canShowReward then
        self:onRewardClick()
        return
    end

    if self.waitRewardTime > 0 then
        return
    end

    self.delayTime = 0
    self.tipTime = 0
    self:hide()
end

return GUIAd